{
  "schema": "brainflow.procedural_guard.v1",
  "name": "cli_arg_length_guard",
  "goal": "Reduce Windows CLI argument-length risk by preferring temp files for large payloads.",
  "rules": [
    {
      "id": "prefer_temp_file",
      "when": "payload_chars_gt_2000",
      "action": "write_temp_file_and_pass_path",
      "notes": "Avoid inline JSON/string args when payload is large; pass file path instead."
    }
  ]
}
